      '• 7天无理由退货\n' +
      '• 15天质量问题换货\n' +
      '• 1年官方保修\n' +
      '• 终身技术支持\n\n' +
      '请问您具体想了解哪方面的售后政策？';
  }

  // 处理对比查询
  handleComparisonQuery(input) {
    const phones = this.productManager.searchByKeyword(input);

    if (phones.length < 2) {
      return '请告诉我您想对比的两款手机型号，比如"iPhone 15和华为Mate 60对比"。';
    }

    const phone1 = phones[0];
    const phone2 = phones[1];

