    response += `| 项目 | ${phone1.model} | ${phone2.model} |\n`;
    response += `|------|----------------|----------------|\n`;
    response += `| 价格 | ¥${phone1.price.toLocaleString()} | ¥${phone2.price.toLocaleString()} |\n`;
    response += `| 处理器 | ${phone1.processor} | ${phone2.processor} |\n`;
