      recommendations,
      `根据您的预算 ¥${budget.toLocaleString()}，`
    );
  }

  // 提取预算金额
  extractBudget(input) {
    // 匹配"3000元"、"3000左右"、"3000以内"等格式
    const patterns = [
      /(\d+)\s*元?\s*(?:左右|上下)/,
      /(\d+)\s*元?\s*(?:以内|以下|之内)/,
      /(\d+)\s*元?\s*(?:以上|之上)/,
      /预算\s*(\d+)/,
      /(\d+)\s*元/
    ];

    for (const pattern of patterns) {
      const match = input.match(pattern);
      if (match) {
        return parseInt(match[1]);
